import React, { useEffect, useState, useRef } from "react";
import { MapContainer, TileLayer, Marker, Popup, ZoomControl } from "react-leaflet";
import L from "leaflet";
import 'leaflet/dist/leaflet.css';
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

const greenIcon = new L.Icon.Default();
const redIcon = new L.Icon.Default();

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);
  const [trendData, setTrendData] = useState([]);
  const trendRef = useRef([]);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        const now = Math.floor(Date.now() / 1000);

        const updatedBuses = data.map((bus, index) => ({
          ...bus,
          lat: Number(bus.lat) || 40.7128,
          lon: Number(bus.lon) || -74.006,
          status: bus.timestamp ? (now - bus.timestamp > 120 ? "ghost" : "active") : "active",
          uniqueKey: `${bus.id}-${index}`
        }));

        setBuses(updatedBuses);

        // Update trend
        const activeCount = updatedBuses.filter(b => b.status === "active").length;
        const ghostCount = updatedBuses.filter(b => b.status === "ghost").length;
        const point = { time: new Date().toLocaleTimeString(), active: activeCount, ghost: ghostCount };

        trendRef.current.push(point);
        if (trendRef.current.length > 24) trendRef.current.shift();
        setTrendData([...trendRef.current]);

        // Add alerts for ghost buses
        const newGhosts = updatedBuses.filter(b => b.status === "ghost");
        newGhosts.forEach(bus => {
          setAlerts(prev => [...prev, { id: bus.uniqueKey, message: `Ghost Bus Detected: ${bus.id}` }]);
        });

      } catch (error) {
        console.error("Error fetching buses:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 5000);
    return () => clearInterval(interval);
  }, []);

  // Remove alerts after 5 seconds
  useEffect(() => {
    if (alerts.length === 0) return;
    const timer = setTimeout(() => {
      setAlerts(prev => prev.slice(1));
    }, 5000);
    return () => clearTimeout(timer);
  }, [alerts]);

  return (
    <div>
      {/* Toggle chart button top-left */}
      <div style={{ position: "absolute", top: 10, left: 10, zIndex: 1000 }}>
        <button
          onClick={() => setShowChart(!showChart)}
          style={{
            padding: "10px 20px",
            backgroundColor: "#007bff",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: "pointer"
          }}
        >
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>

        {showChart && (
          <div style={{
            width: "350px",
            height: "200px",
            marginTop: "10px",
            backgroundColor: "white",
            borderRadius: "8px",
            padding: "5px",
            overflowX: "auto"
          }}>
            <LineChart width={340} height={180} data={trendData}>
              <XAxis dataKey="time" />
              <YAxis />
              <Tooltip />
              <CartesianGrid stroke="#f5f5f5" />
              <Line type="monotone" dataKey="active" stroke="green" />
              <Line type="monotone" dataKey="ghost" stroke="red" />
            </LineChart>
          </div>
        )}
      </div>

      {/* Ghost alerts top-right */}
      <div style={{ position: "absolute", top: 10, right: 10, zIndex: 1000 }}>
        {alerts.map(alert => (
          <div key={alert.id} style={{
            backgroundColor: "red",
            color: "white",
            padding: "8px 12px",
            marginBottom: "5px",
            borderRadius: "5px",
            boxShadow: "0px 0px 5px rgba(0,0,0,0.3)"
          }}>
            {alert.message}
          </div>
        ))}
      </div>

      <MapContainer
        center={buses.length ? [buses[0].lat, buses[0].lon] : [40.7128, -74.006]}
        zoom={11}
        style={{ height: "100vh", width: "100%" }}
        scrollWheelZoom={true}
        zoomControl={false}
      >
        <ZoomControl position="topleft" />
        <TileLayer
          url="https://cartodb-basemaps-a.global.ssl.fastly.net/light_all/{z}/{x}/{y}{r}.png"
          attribution=""
        />

        {buses.map((bus) => (
          <Marker
            key={bus.uniqueKey}
            position={[bus.lat, bus.lon]}
            icon={bus.status === "ghost" ? redIcon : greenIcon}
          >
            <Popup>
              <b>Bus ID:</b> {bus.id} <br />
              <b>Status:</b> {bus.status} <br />
              <b>Lat/Lon:</b> {bus.lat.toFixed(5)}, {bus.lon.toFixed(5)}
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
};

export default MapComponent;
